// TestWebhookRouterRoutesCommentEventWhenFeatureEnabled verifies that COMMENT
// webhook events are routed through the agent pipeline when features.comment_reply is
// enabled. This is the core bug: before the fix, COMMENT events were silently dropped.
func TestWebhookRouterRoutesCommentEventWhenFeatureEnabled(t *testing.T) {
	msgBus := bus.New()
	target := &Channel{
		BaseChannel: channels.NewBaseChannel(channels.TypePancake, msgBus, nil),
		pageID:      "page-123",
		platform:    "facebook",
		config: pancakeInstanceConfig{
			PageID: "page-123",
			Features: struct {
				InboxReply   bool `json:"inbox_reply"`
				CommentReply bool `json:"comment_reply"`
			}{
				InboxReply:   true,
				CommentReply: true,
			},
		},
	}
	router := &webhookRouter{
		instances: map[string]*Channel{
			"page-123": target,
		},
	}

	body := `{
		"page_id": "page-123",
		"event_type": "messaging",
		"data": {
			"conversation": {
				"id": "page-123_user-1",
				"type": "COMMENT",
				"from": {
					"id": "user-1",
					"name": "Customer"
				}
			},
			"message": {
				"id": "msg-comment-1",
				"message": "awesome post!"
			}
		}
	}`

	req := httptest.NewRequest(http.MethodPost, "/channels/pancake/webhook", strings.NewReader(body))
	w := httptest.NewRecorder()
	router.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("status = %d, want %d", w.Code, http.StatusOK)
	}

	ctx, cancel := context.WithTimeout(context.Background(), 50*time.Millisecond)
	defer cancel()

	msg, ok := msgBus.ConsumeInbound(ctx)
	if !ok {
		t.Fatal("expected COMMENT conversation webhook to be published when comment_reply is enabled")
	}
	if got, want := msg.Metadata["pancake_mode"], "comment"; got != want {
		t.Fatalf("metadata.pancake_mode = %q, want %q", got, want)
	}
	if got, want := msg.Metadata["conversation_type"], "COMMENT"; got != want {
		t.Fatalf("metadata.conversation_type = %q, want %q", got, want)
	}
}

